import{M as e,O as t,h as n,m as r,p as i,s as a,u as o}from"./chunks/runtime-core.esm-bundler.DGewWfie.js";import{t as s}from"./chunks/plugin-vue_export-helper.BDNMzG2s.js";var c=JSON.parse(`{"title":"Minecraft 伺服器","description":"東東的創世神伺服器紀錄，整理伺服器特色、歷史、社群與經營經驗。","frontmatter":{"title":"Minecraft 伺服器","description":"東東的創世神伺服器紀錄，整理伺服器特色、歷史、社群與經營經驗。","outline":[2,3]},"headers":[],"relativePath":"minecraft.md","filePath":"minecraft.md","lastUpdated":1781683122000}`),l={name:`minecraft.md`},u={id:`minecraft-伺服器`,tabindex:`-1`};function d(s,c,l,d,f,p){let m=e(`Badge`);return t(),o(`div`,null,[a(`h1`,u,[c[0]||=r(`Minecraft 伺服器 `,-1),n(m,{type:`tip`,text:`Since 2013`}),c[1]||=r(),c[2]||=a(`a`,{class:`header-anchor`,href:`#minecraft-伺服器`,"aria-label":`Permalink to “Minecraft 伺服器”`},`​`,-1)]),c[3]||=i(`<div class="lead-panel"><h2>東東的創世神伺服器</h2><p>從 Minecraft 1.5.2 時代開始經營的長期社群專案，累積伺服器架設、玩家管理、網站維護與內容營運經驗。</p></div><nav class="table-of-contents"><ul><li><a href="#快速資訊">快速資訊</a></li><li><a href="#伺服器特色">伺服器特色</a></li><li><a href="#發展時間軸">發展時間軸</a></li><li><a href="#站務經驗">站務經驗</a></li><li><a href="#相關連結">相關連結</a></li></ul></nav><h2 id="快速資訊" tabindex="-1">快速資訊 <a class="header-anchor" href="#快速資訊" aria-label="Permalink to “快速資訊”">​</a></h2><div class="metric-grid"><div class="metric"><strong>伺服器名稱</strong><span>東東的創世神伺服器（DDS）</span></div><div class="metric"><strong>開始時間</strong><span>2013 年，Minecraft 1.5.2 時代</span></div><div class="metric"><strong>網站</strong><span><a href="https://wuc656.com">wuc656.com</a></span></div><div class="metric"><strong>社群</strong><span>Discord、Facebook 粉絲專頁與社團</span></div></div><h2 id="伺服器特色" tabindex="-1">伺服器特色 <a class="header-anchor" href="#伺服器特色" aria-label="Permalink to “伺服器特色”">​</a></h2><table tabindex="0"><thead><tr><th>類型</th><th>內容</th></tr></thead><tbody><tr><td>遊戲模式</td><td>插件生存、24 小時開服</td></tr><tr><td>主要版本</td><td>1.12.2，也曾支援 1.19.4 等版本</td></tr><tr><td>核心系統</td><td>Mcmmo 生活技能、住宅區、公會、寵物</td></tr><tr><td>社群機制</td><td>優質玩家驗證、新手引導、規則與指令教學</td></tr><tr><td>經營方式</td><td>自架服務、網站維護、Discord 與 Facebook 社群支援</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">經營重點</p><p>這個伺服器不只是遊戲專案，也是一個長期練習技術、營運、文件整理與社群溝通的實戰場域。</p></div><h2 id="發展時間軸" tabindex="-1">發展時間軸 <a class="header-anchor" href="#發展時間軸" aria-label="Permalink to “發展時間軸”">​</a></h2><div class="timeline"><div class="timeline-item"><h3>2013：建立伺服器</h3><p>以 Minecraft 1.5.2 起步，開始接觸伺服器架設、插件設定、網路與玩家管理。</p></div><div class="timeline-item"><h3>2013 - 2020：持續經營</h3><p>累積玩家社群、規則、網站資料、教學文件與活動內容。</p></div><div class="timeline-item"><h3>2020：重新開服</h3><p>曾因經費問題短暫關服，之後升級光纖網路並重新投入營運。</p></div><div class="timeline-item"><h3>2020 - 至今：維護與延伸</h3><p>持續保留伺服器、社群與網站資產，並將經驗延伸到個人網站與工具開發。</p></div></div><h2 id="站務經驗" tabindex="-1">站務經驗 <a class="header-anchor" href="#站務經驗" aria-label="Permalink to “站務經驗”">​</a></h2><ul><li><strong>伺服器架設</strong>：處理版本、插件、資料備份、網路與硬體資源。</li><li><strong>玩家支援</strong>：回應新手問題、管理規則、協助帳號與遊戲內權限。</li><li><strong>文件維護</strong>：撰寫規則、指令教學、驗證流程與伺服器介紹。</li><li><strong>社群經營</strong>：維護 Discord、Facebook 粉絲專頁與社團。</li><li><strong>內容產出</strong>：製作宣傳圖片、影片與 YouTube 內容。</li></ul><h2 id="相關連結" tabindex="-1">相關連結 <a class="header-anchor" href="#相關連結" aria-label="Permalink to “相關連結”">​</a></h2><div class="link-grid"><div class="link-card"><strong>官方網站</strong><span><a href="https://wuc656.com">wuc656.com</a></span></div><div class="link-card"><strong>Discord</strong><span><a href="https://discord.gg/VSeYAGN">加入伺服器社群</a></span></div><div class="link-card"><strong>Facebook 粉絲專頁</strong><span><a href="https://www.facebook.com/wud656/">東東的創世神伺服器</a></span></div><div class="link-card"><strong>Facebook 社團</strong><span><a href="https://www.facebook.com/groups/dongserver/">玩家社團</a></span></div></div><details class="details custom-block"><summary>可延伸整理的文件</summary><ul><li>伺服器規則與指令頁</li><li>插件與功能介紹</li><li>優質玩家驗證流程</li><li>伺服器維護紀錄</li><li>伺服器宣傳素材與影片索引</li></ul></details>`,14)])}var f=s(l,[[`render`,d]]);export{c as __pageData,f as default};